    "account", "accounts", "settings", "billing", "payments", "oauth", "sso",
    "www", "mail", "email", "ftp", "static", "assets", "cdn", "null", "undefined",
    "undefined", "delete", "create", "me", "profile", "official", "status",
}

BANNED_USERNAME_SUBSTRINGS = {
    "nazi", "hitler", "kkk", "terrorist", "rapist", "suicide", "selfharm",
}

DISPOSABLE_DOMAINS = {
    "10minutemail.com", "guerrillamail.com", "mailinator.com", "tempmail.com",
    "temp-mail.org", "throwawaymail.com", "yopmail.com", "trashmail.com",
    "sharklasers.com", "getnada.com", "dispostable.com", "fakeinbox.com",
}

RESERVED_EMAIL_DOMAINS = {
    "localhost", "local", "example.com", "example.net", "example.org",
    "invalid", "test",
}

COMMON_PASSWORDS = {
    "password", "password1", "password123", "12345678", "123456789",
    "qwerty123", "letmein", "welcome", "admin123", "iloveyou",
    "monkey", "dragon", "football", "baseball",
}

USERNAME_RE = re.compile(r"^[a-z][a-z0-9_]{2,31}$")
CONTROL_OR_BIDI = {
    "Cc", "Cf",
}


def get_db() -> Session:
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()


def error(field: str, code: str, message: str) -> dict[str, str]:
    return {"field": field, "code": code, "message": message}


def json_error(status_code: int, errors: list[dict[str, str]]) -> JSONResponse:
    return JSONResponse(
        status_code=status_code,
        content={"ok": False, "errors": errors},
    )


def client_ip(request: Request) -> str:
    # Do not trust X-Forwarded-For unless your reverse proxy strips spoofed headers.
    return request.client.host if request.client else "unknown"


def sha256_hex(value: str) -> str:
    return hashlib.sha256(value.encode("utf-8")).hexdigest()


def hmac_lookup(value: str) -> str:
    return hmac.new(
        PEPPER.encode("utf-8"),
        value.encode("utf-8"),
        hashlib.sha256,
    ).hexdigest()


def has_control_or_bidi(value: str) -> bool:
    return any(unicodedata.category(ch) in CONTROL_OR_BIDI for ch in value)


def normalize_text(value: str) -> str:
    return unicodedata.normalize("NFKC", value)


def collapse_spaces(value: str) -> str:
    return re.sub(r"\s+", " ", value).strip()


def add_required_string_errors(
    payload: dict[str, Any],
    field: str,
    errors: list[dict[str, str]],
) -> str | None:
    if field not in payload:
        errors.append(error(field, "required", f"{field} is required."))
        return None
    if not isinstance(payload[field], str):
        errors.append(error(field, "invalid_type", f"{field} must be a string."))
        return None
    return payload[field]


def validate_email_field(raw: str | None, errors: list[dict[str, str]]) -> str | None:
    if raw is None:
        return None

    if raw != raw.strip():
        errors.append(error("email", "surrounding_whitespace", "Email must not have surrounding whitespace."))

    value = normalize_text(raw.strip())

    if not value:
        errors.append(error("email", "empty", "Email is required."))
        return None

    if len(value) > MAX_EMAIL_LEN:
        errors.append(error("email", "too_long", "Email is too long."))

    if has_control_or_bidi(value) or "\r" in value or "\n" in value:
        errors.append(error("email", "unsafe_characters", "Email contains unsafe control characters."))

    if any(ch.isspace() for ch in value):
        errors.append(error("email", "whitespace", "Email must not contain whitespace."))

    if value.count("@") != 1:
        errors.append(error("email", "invalid_format", "Email must contain exactly one @ sign."))
        return None

    local, _, domain = value.partition("@")

    if not local or not domain:
        errors.append(error("email", "invalid_format", "Email must include a local part and domain."))
        return None

    if local.startswith(".") or local.endswith(".") or ".." in local:
        errors.append(error("email", "invalid_local_part", "Email local part is not valid."))

    if local.startswith('"') or local.endswith('"'):
        errors.append(error("email", "quoted_local_part", "Quoted email local parts are not allowed."))

    if domain.startswith("[") or domain.endswith("]"):
        errors.append(error("email", "domain_literal", "IP address email domains are not allowed."))

    try:
        checked = validate_email(
            value,
            check_deliverability=True,
            allow_smtputf8=False,
            allow_quoted_local=False,
            allow_domain_literal=False,
        )
    except EmailNotValidError as exc:
        errors.append(error("email", "invalid_email", str(exc)))
        return None

    ascii_email = checked.ascii_email or checked.normalized
    normalized = ascii_email.casefold()
    normalized_domain = checked.ascii_domain.casefold()

    labels = normalized_domain.split(".")
    if len(normalized_domain) > 253 or any(len(label) > 63 for label in labels):
        errors.append(error("email", "invalid_domain_length", "Email domain length is invalid."))

    if len(labels) < 2:
        errors.append(error("email", "missing_tld", "Email domain must include a public suffix."))

    if labels[-1].isdigit() or len(labels[-1]) < 2:
        errors.append(error("email", "invalid_tld", "Email top-level domain is invalid."))

    if normalized_domain in RESERVED_EMAIL_DOMAINS or any(
        normalized_domain.endswith("." + d) for d in RESERVED_EMAIL_DOMAINS
    ):
        errors.append(error("email", "reserved_domain", "Email domain is not allowed."))

    if normalized_domain in DISPOSABLE_DOMAINS or any(
        normalized_domain.endswith("." + d) for d in DISPOSABLE_DOMAINS
    ):
        errors.append(error("email", "disposable_domain", "Disposable email addresses are not allowed."))

    return normalized


def validate_username(raw: str | None, errors: list[dict[str, str]]) -> str | None:
    if raw is None:
        return None

    if raw != raw.strip():
        errors.append(error("username", "surrounding_whitespace", "Username must not have surrounding whitespace."))

    normalized = normalize_text(raw.strip())

    if normalized != raw.strip():
        errors.append(error("username", "unicode_normalization", "Username contains confusable Unicode characters."))

    username = normalized.casefold()

    if not username:
        errors.append(error("username", "empty", "Username is required."))
        return None

    if len(username) < 3:
        errors.append(error("username", "too_short", "Username must be at least 3 characters."))

    if len(username) > MAX_USERNAME_LEN:
        errors.append(error("username", "too_long", "Username must be at most 32 characters."))

    if not username.isascii():
        errors.append(error("username", "non_ascii", "Username must use ASCII characters only."))

    if has_control_or_bidi(username):
        errors.append(error("username", "unsafe_characters", "Username contains unsafe characters."))

    if not USERNAME_RE.fullmatch(username):
        errors.append(
            error(
                "username",
                "invalid_characters",
                "Username must start with a letter and contain only lowercase letters, numbers, and underscores.",
            )
        )

    if username.startswith("_") or username.endswith("_") or "__" in username:
        errors.append(error("username", "invalid_underscore", "Username must not start/end with or repeat underscores."))

    if username in RESERVED_USERNAMES:
        errors.append(error("username", "reserved", "Username is reserved."))

    if any(term in username for term in BANNED_USERNAME_SUBSTRINGS):
        errors.append(error("username", "blocked_content", "Username is not allowed."))

    if username.isdigit():
        errors.append(error("username", "all_digits", "Username cannot be only digits."))

    return username


def validate_display_name(raw: str | None, errors: list[dict[str, str]]) -> str | None:
    if raw is None:
        return None

    normalized = collapse_spaces(normalize_text(raw))

    if not normalized:
        errors.append(error("display_name", "empty", "Display name is required."))
        return None

    if len(normalized) > MAX_DISPLAY_NAME_LEN:
        errors.append(error("display_name", "too_long", "Display name must be at most 80 characters."))

    if len(normalized.encode("utf-8")) > 160:
        errors.append(error("display_name", "too_many_bytes", "Display name is too large."))

    if has_control_or_bidi(normalized):
        errors.append(error("display_name", "unsafe_characters", "Display name contains unsafe Unicode characters."))

    stripped = bleach.clean(normalized, tags=[], attributes={}, strip=True)
    if stripped != normalized or any(ch in normalized for ch in "<>`"):
        errors.append(error("display_name", "markup_not_allowed", "Display name must not contain HTML or script markup."))

    if re.search(r"(?i)\b(?:https?://|javascript:|data:)", normalized):
        errors.append(error("display_name", "url_not_allowed", "Display name must not contain URLs."))

    if any(term in normalized.casefold() for term in BANNED_USERNAME_SUBSTRINGS):
        errors.append(error("display_name", "blocked_content", "Display name is not allowed."))

    return html.escape(stripped, quote=False)


def password_classes(password: str) -> int:
    return sum(
        [
            any(ch.islower() for ch in password),
            any(ch.isupper() for ch in password),
            any(ch.isdigit() for ch in password),
            any(ch in string.punctuation or unicodedata.category(ch).startswith("S") for ch in password),
        ]
    )


def looks_sequential(password: str) -> bool:
    lowered = password.casefold()
    sequences = [
        "abcdefghijklmnopqrstuvwxyz",
        "zyxwvutsrqponmlkjihgfedcba",
        "0123456789",
        "9876543210",
        "qwertyuiop",
        "poiuytrewq",
        "asdfghjkl",
        "lkjhgfdsa",
    ]
    return any(seq[i : i + 5] in lowered for seq in sequences for i in range(len(seq) - 4))


def too_similar(a: str, b: str) -> bool:
    if not a or not b:
        return False
    a = a.casefold()
    b = b.casefold()
    return a in b or b in a or SequenceMatcher(None, a, b).ratio() >= 0.72


async def is_breached_password(password: str) -> bool | None:
    digest = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = digest[:5], digest[5:]
    url = f"https://api.pwnedpasswords.com/range/{prefix}"

    try:
        async with httpx.AsyncClient(timeout=2.5) as client:
            response = await client.get(url, headers={"Add-Padding": "true"})
            response.raise_for_status()
    except httpx.HTTPError:
        return None

    for line in response.text.splitlines():
        candidate, _, count = line.partition(":")
        if hmac.compare_digest(candidate, suffix):
            return int(count or "0") > 0

    return False


async def validate_password(
    raw: str | None,
    email_value: str | None,
    username: str | None,
    display_name: str | None,
    errors: list[dict[str, str]],
) -> str | None:
    if raw is None:
        return None

    password = normalize_text(raw)

    if not password:
        errors.append(error("password", "empty", "Password is required."))
        return None

    if raw != raw.strip():
        errors.append(error("password", "surrounding_whitespace", "Password must not start or end with whitespace."))

    if "\x00" in password or has_control_or_bidi(password):
        errors.append(error("password", "unsafe_characters", "Password contains unsafe characters."))

    if len(password) < 12:
        errors.append(error("password", "too_short", "Password must be at least 12 characters."))

    if len(password) > MAX_PASSWORD_CHARS:
        errors.append(error("password", "too_long", "Password must be at most 128 characters."))

    if len(password.encode("utf-8")) > MAX_PASSWORD_BYTES:
        errors.append(error("password", "too_many_bytes", "Password is too large."))

    if password_classes(password) < 3:
        errors.append(
            error(
                "password",
                "insufficient_complexity",
                "Password must contain at least 3 of: lowercase, uppercase, number, symbol.",
            )
        )

    lowered = password.casefold()

    if lowered in COMMON_PASSWORDS:
        errors.append(error("password", "common_password", "Password is too common."))

    if len(set(lowered)) <= 4:
        errors.append(error("password", "low_variety", "Password has too little character variety."))

    if re.search(r"(.)\1{4,}", lowered):
        errors.append(error("password", "repeated_characters", "Password contains too many repeated characters."))

    if looks_sequential(password):
        errors.append(error("password", "sequential", "Password contains an easy-to-guess sequence."))

    email_local = email_value.split("@", 1)[0] if email_value and "@" in email_value else ""
    email_domain = email_value.split("@", 1)[1].split(".", 1)[0] if email_value and "@" in email_value else ""

    for label, value in [
        ("username", username),
        ("email", email_local),
        ("email domain", email_domain),
        ("display name", display_name),
    ]:
        if value and len(value) >= 3 and too_similar(password, value):
            errors.append(error("password", "too_similar", f"Password is too similar to your {label}."))
            break

    if not any(e["field"] == "password" for e in errors):
        breached = await is_breached_password(password)
        if breached is True:
            errors.append(error("password", "breached", "Password has appeared in a known breach."))
        elif breached is None and os.getenv("HIBP_FAIL_CLOSED", "1") == "1":
            errors.append(error("password", "breach_check_unavailable", "Password breach check is temporarily unavailable."))

    return password


async def enforce_rate_limit(key: str, limit: int, window: int) -> JSONResponse | None:
    allowed, retry_after = limiter.check(key, limit, window)
    if allowed:
        return None

    return JSONResponse(
        status_code=429,
        headers={"Retry-After": str(retry_after)},
        content={
            "ok": False,
            "errors": [
                {
                    "field": "non_field",
                    "code": "rate_limited",
                    "message": "Too many registration attempts. Try again later.",
                }
            ],
        },
    )


def validate_request_security(request: Request) -> list[dict[str, str]]:
    errors: list[dict[str, str]] = []

    content_type = request.headers.get("content-type", "")
    if "application/json" not in content_type.casefold():
        errors.append(error("non_field", "invalid_content_type", "Content-Type must be application/json."))

    origin = request.headers.get("origin")
    if origin and origin not in TRUSTED_ORIGINS:
        errors.append(error("non_field", "invalid_origin", "Request origin is not allowed."))

    if request.headers.get("sec-fetch-site") == "cross-site":
        errors.append(error("non_field", "cross_site_request", "Cross-site registration requests are not allowed."))

    return errors


@app.middleware("http")
async def security_headers(request: Request, call_next):
    response = await call_next(request)
    response.headers["X-Content-Type-Options"] = "nosniff"
    response.headers["Referrer-Policy"] = "no-referrer"
    response.headers["Cache-Control"] = "no-store"
    response.headers["Permissions-Policy"] = "geolocation=(), microphone=(), camera=()"
    return response


@app.post("/api/register")
async def register(request: Request, db: Session = Depends(get_db)):
    ip = client_ip(request)

    limited = await enforce_rate_limit(f"register:ip:min:{ip}", limit=5, window=60)
    if limited:
        return limited

    limited = await enforce_rate_limit(f"register:ip:hour:{ip}", limit=30, window=3600)
    if limited:
        return limited

    security_errors = validate_request_security(request)

    body = await request.body()
    if len(body) > MAX_BODY_BYTES:
        return json_error(
            413,
            [error("non_field", "payload_too_large", "Request body is too large.")],
        )

    try:
        payload = json.loads(body)
    except json.JSONDecodeError:
        return json_error(
            400,
            [error("non_field", "invalid_json", "Request body must be valid JSON.")],
        )

    if not isinstance(payload, dict):
        return json_error(
            400,
            [error("non_field", "invalid_body", "Request body must be a JSON object.")],
        )

    errors = security_errors[:]

    allowed_fields = {"email", "username", "password", "display_name"}
    unknown = sorted(set(payload) - allowed_fields)
    for field in unknown:
        errors.append(error(field, "unknown_field", "Unknown field is not allowed."))

    raw_email = add_required_string_errors(payload, "email", errors)
    raw_username = add_required_string_errors(payload, "username", errors)
    raw_password = add_required_string_errors(payload, "password", errors)
    raw_display_name = add_required_string_errors(payload, "display_name", errors)

    email_value = validate_email_field(raw_email, errors)
    username = validate_username(raw_username, errors)
    display_name = validate_display_name(raw_display_name, errors)

    if email_value:
        limited = await enforce_rate_limit(f"register:email:{sha256_hex(email_value)}", limit=3, window=3600)
        if limited:
            return limited

    if username:
        limited = await enforce_rate_limit(f"register:username:{sha256_hex(username)}", limit=10, window=3600)
        if limited:
            return limited

    password = await validate_password(raw_password, email_value, username, display_name, errors)

    if errors:
        return json_error(422, errors)

    assert email_value is not None
    assert username is not None
    assert display_name is not None
    assert password is not None

    # Hash before uniqueness checks so valid duplicate and valid new registrations have similar cost.
    password_hash = password_hasher.hash(password)

    email_lookup_hash = hmac_lookup(email_value)
    now = datetime.now(timezone.utc)

    try:
        existing = db.execute(
            select(users.c.id).where(
                or_(
                    users.c.email_lookup_hash == email_lookup_hash,
                    users.c.username == username,
                )
            )
        ).first()

        if not existing:
            db.execute(
                insert(users).values(
                    email=email_value,
                    email_lookup_hash=email_lookup_hash,
                    username=username,
                    display_name=display_name,
                    password_hash=password_hash,
                    is_email_verified=False,
                    created_at=now,
                )
            )
            db.commit()
        else:
            db.rollback()

    except IntegrityError:
        # Handles concurrent duplicate registrations without leaking which identifier collided.
        db.rollback()

    return JSONResponse(
        status_code=202,
        content={
            "ok": True,
            "message": "If the registration can be completed, a verification email will be sent.",
        },
    )
